import React from "react";
import { useNavigate } from "react-router-dom";

type Seat = {
  seatNumber: string;
  isAvailable: boolean;
  row: number;
  column: number;
};

type Bus = {
  _id: string;
  name: string;
  departureCity: string;
  arrivalCity: string;
  departureTime: string;
  arrivalTime: string;
  price: number;
  seatType: string;
  isAC: boolean;
  seats: Seat[];
};

type Props = {
  bus: Bus;
};

const BusCard: React.FC<Props> = ({ bus }) => {
  const navigate = useNavigate();

  return (
    <div className="card bus-card">
      <h3>{bus.name}</h3>
      <p>
        {bus.departureCity} to {bus.arrivalCity}
      </p>
      <p>
        Departure: {new Date(bus.departureTime).toLocaleString()} | Arrival: {new Date(bus.arrivalTime).toLocaleString()}
      </p>
      <p>
        {bus.seatType} | {bus.isAC ? "AC" : "Non-AC"}
      </p>
      <p>Price: INR {bus.price}</p>
      <button onClick={() => navigate(`/seats/${bus._id}`)}>Book</button>
    </div>
  );
};

export type { Bus };
export default BusCard;
